    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout - if either sensor is stale for > 1000ms, go to safe all-off */
    bool has_timeout = false;
    if (!controller->has_valid_temperature) {
        if (controller->last_temperature_ms == 0U || 
            (input.now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            has_timeout = true;
        }
    }
    if (!controller->has_valid_level) {
        if (controller->last_level_ms == 0U || 
            (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            has_timeout = true;
        }
    }

    /* If we have no valid sensor data yet, stay safe idle */
    if (!controller->has_valid_temperature && !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = false;
        return output;
    }

    /* If either sensor is stale, go to safe all-off */
    if (has_timeout) {
        controller_set_safe_idle(controller);
        output.inlet_open = controller->inlet_open;
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = true;
        return output;
    }

    bool current_inlet_open = controller->inlet_open;
    bool current_heater_on = controller->heater_on;
    int current_temp = controller->last_temperature_c;
    int current_level = controller->last_level;

    /* Check if level is low (< 60) - need to fill */
    if (current_level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* Keep heater off if level < 55 */
        if (current_level >= CONTROLLER_MIN_HEATING_LEVEL) {
            controller->inlet_open = true;
            controller->heater_on = false;
        } else {
            controller->inlet_open = true;
            controller->heater_on = false;
        }
    } else {
        /* Level is safe (>= 60), check temperature control */
        if (current_level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
            /* Level too high - close inlet and heater off */
            controller->inlet_open = false;
            controller->heater_on = false;
        } else if (current_temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temp, level safe - close inlet, turn on heater */
            controller->inlet_open = false;
            controller->heater_on = true;
        } else if (current_temp >= CONTROLLER_TEMP_LOW_THRESHOLD && current_temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* Temp in low band [45, 47), close inlet, hold previous safe heater state */
            controller->inlet_open = false;
            /* Hold the previous heater state - check if we were heating before */
            if (controller->heater_on) {
                controller->heater_on = true;
            } else {
                controller->heater_on = false;
            }
        } else if (current_temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && current_temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Temp in upper band [47, 48], check if rising */
            bool is_rising = (current_temp > controller->previous_temperature_c);
            if (is_rising) {
                /* Temperature rising - turn off heater early */
                controller->inlet_open = false;
                controller->heater_on = false;
            } else {
                /* Temp not rising, hold previous safe heater state */
                controller->inlet_open = false;
                if (controller->heater_on) {
                    controller->heater_on = true;
                } else {
                    controller->heater_on = false;
                }
            }
        } else if (current_temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Temp too high - close inlet and heater off */
            controller->inlet_open = false;
            controller->heater_on = false;
        }
    }

    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

